  ('elementary-0a2fc18c-moex-00954', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設一個追求利潤最大的獨占廠商面對負斜率的市場需求曲線。當此廠商生產第10單位時，此廠商：', '["生產第10單位的平均成本小於生產第9單位所得到的平均成本", "生產10單位所得到的總收益大於生產9單位所得到的總收益", "生產第10單位所得到的平均收益大於生產第9單位所得到的平均收益", "生產第10單位所得到的邊際收益小於生產第9單位所得到的邊際收益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00955', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '對一個追求利潤最大的獨占廠商而言，其邊際收益為零的產量亦為：', '["平均收益為零的產量", "利潤最大的產量", "總收益最大的產量", "邊際成本為零的產量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00956', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設一個完全競爭市場中所有廠商都有相同的成本結構，且市場的需求增加。在短期及其他條件不變下， 下列何者正確？', '["個別競爭廠商的需求曲線不會改變", "個別競爭廠商的需求曲線會變得更無彈性", "個別競爭廠商的需求曲線會變得更有彈性", "所有競爭廠商的利潤會增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00957', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '獨占者執行差別取價時，下列敘述何者正確？', '["將消費者剩餘轉變成經濟利潤", "將生產者剩餘轉變成經濟利潤", "對所有消費者索取相同的價格", "產量低於執行單一定價時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00958', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設市場需求函數為Q=12－P，市場供給函數為Q=2P，其中Q為數量而P為價格。在市場均衡時，生 產者剩餘為何？', '["$16", "$20", "$24", "$32"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00959', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', 'B商品所在的市場是一個完全競爭市場，其短期的市場供給曲線為正斜率，同時就消費者而言，B商品是 正常財。如果所有消費者的所得都減少時，下列針對新的短期市場均衡之敘述，何者正確？', '["短期均衡的廠商家數一定會增加", "短期均衡的廠商家數一定會減少", "短期的市場均衡數量一定會上升", "短期的市場均衡數量一定會下降"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00960', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '在完全競爭的勞動市場供需分析模型中，當廠商的生產技術進步，因而提升員工的邊際產出時，下列敘 述何者正確？', '["勞動供給會增加，勞動需求不變", "勞動供給會減少，勞動需求不變", "勞動供給不變，勞動需求會增加", "勞動供給不變，勞動需求會減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00961', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '下列那項假設是造成個別廠商的勞動需求曲線為負斜率的主要原因？', '["勞工不願意加班", "廠商不喜歡僱用太多勞工", "勞動的平均產量遞減", "勞工的邊際產量遞減"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00962', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '有關富彈性的勞動需求（elasticlabordemand），下列敘述何者正確？', '["指的是相較其他勞動需求曲線，相同幅度薪資的增加，會造成相對較大幅度勞動需求數量之減少", "指的是勞動需求數量減少的幅度高於薪資減少的幅度", "當薪資提高一個百分點時，勞動需求數量減少低於一個百分點", "當薪資提高時，薪資變動的幅度小於勞動需求數量減少的幅度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "a995a09c8dd5", "answer_pdf_sha1": "214c7af8bde3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
